        questions: [
          { id: 'ppl-m1-l2-q1', topic: 'Weather', type: 'multiple-choice', text: 'How long is a standard Terminal Aerodrome Forecast (TAF) valid?', options: ['24 to 30 hours', '6 to 12 hours', '48 hours', '12 to 18 hours'], correctAnswer: 0, explanation: 'Standard TAFs are issued four times daily and are valid for 24 to 30 hours. Extended TAFs for some airports may cover up to 36 hours.', reference: 'AIM 7-1-30' },
          { id: 'ppl-m1-l2-q2', topic: 'Weather', type: 'multiple-choice', text: 'In a TAF, what does the change group "TEMPO" indicate?', options: ['Temporary fluctuations lasting less than one hour and covering less than half the period', 'A permanent change expected within 30 minutes', 'Temperature variations in the forecast period', 'A change expected to last more than 6 hours'], correctAnswer: 0, explanation: 'TEMPO indicates temporary fluctuations expected to last less than one hour at a time and occur during less than half of the indicated time period.', reference: 'AIM 7-1-30' },
          { id: 'ppl-m1-l2-q3', topic: 'Weather', type: 'multiple-choice', text: 'Which of the following best describes a cold front?', options: ['A fast-moving front with steep slope, often producing squall lines and cumulonimbus clouds', 'A slow-moving front with gradual lift producing widespread stratus and drizzle', 'A stationary boundary between air masses of equal temperature', 'A front that forms when two cold air masses meet'], correctAnswer: 0, explanation: 'Cold fronts move faster than warm fronts, have a steep slope, and can produce violent weather including squall lines, cumulonimbus clouds, and thunderstorms ahead of and along the front.', reference: 'FAA-H-8083-25B Ch.12' },
          { id: 'ppl-m1-l2-q4', topic: 'Weather', type: 'multiple-choice', text: 'An AIRMET Sierra (AIRMET S) is issued to warn of:', options: ['IFR conditions and mountain obscuration', 'Severe turbulence and strong surface winds', 'Icing and freezing level data', 'Severe thunderstorms and hail'], correctAnswer: 0, explanation: 'AIRMET Sierra warns of IFR conditions (ceiling <1,000 ft and/or visibility <3 SM) and mountain obscuration. These are significant for VFR pilots.', reference: 'AIM 7-1-6' },
          { id: 'ppl-m1-l2-q5', topic: 'Weather', type: 'multiple-choice', text: 'What does AIRMET Zulu (AIRMET Z) address?', options: ['Icing and freezing levels', 'Turbulence and strong surface winds', 'IFR conditions and low ceilings', 'Volcanic ash and dust storms'], correctAnswer: 0, explanation: 'AIRMET Zulu addresses moderate icing and provides freezing level data. It is especially important for aircraft not certified for flight into known icing conditions.', reference: 'AIM 7-1-6' },
          { id: 'ppl-m1-l2-q6', topic: 'Weather', type: 'multiple-choice', text: 'A SIGMET (WS) is issued for which type of weather?', options: ['Severe icing, severe turbulence, dust storms, or volcanic ash affecting aircraft', 'Moderate turbulence over mountainous terrain', 'IFR conditions at a specific airport', 'Frost on the ground at airports'], correctAnswer: 0, explanation: 'SIGMETs are issued for severe or extreme conditions hazardous to all aircraft: severe/extreme turbulence, severe icing not associated with thunderstorms, dust/sandstorms, and volcanic ash. Valid 6 hours (4 hours for convective).', reference: 'AIM 7-1-6' },
          { id: 'ppl-m1-l2-q7', topic: 'Weather', type: 'multiple-choice', text: 'What weather is typically associated with a warm front?', options: ['Low ceilings, stratus clouds, drizzle, and reduced visibility ahead of the front', 'Cumulonimbus clouds, heavy rain, and gusty winds at the front', 'Clear skies and good visibility directly behind the front', 'Dry air and stable conditions for several hundred miles ahead'], correctAnswer: 0, explanation: 'Warm fronts have a gradual slope, which causes warm moist air to rise slowly, producing wide areas of stratus clouds, low ceilings, and drizzle or light rain ahead of the front.', reference: 'FAA-H-8083-25B Ch.12' },
          { id: 'ppl-m1-l2-q8', topic: 'Weather', type: 'multiple-choice', text: 'A Pilot Report (PIREP) coded "UA" is:', options: ['A routine PIREP', 'An urgent PIREP', 'An automated PIREP from onboard sensors', 'A PIREP from an unidentified aircraft'], correctAnswer: 0, explanation: '"UA" designates a routine PIREP. "UUA" designates an urgent PIREP, typically filed when encountering conditions such as severe turbulence, severe icing, or low-level wind shear.', reference: 'AIM 7-1-22' },
          { id: 'ppl-m1-l2-q9', topic: 'Weather', type: 'true-false', text: 'AIRMET Tango (AIRMET T) is issued to warn of moderate turbulence, sustained surface winds of 30 knots or more, and non-convective low-level wind shear.', options: ['True', 'False'], correctAnswer: 0, explanation: 'True. AIRMET Tango covers moderate turbulence, sustained surface winds of 30 knots or more at the surface, and non-convective low-level wind shear below 2,000 feet AGL.', reference: 'AIM 7-1-6' },
          { id: 'ppl-m1-l2-q10', topic: 'Weather', type: 'true-false', text: 'In a TAF, the change group "FM" (from) indicates a rapid, permanent change in conditions expected within 30 minutes.', options: ['True', 'False'], correctAnswer: 0, explanation: 'True. FM (from) indicates a rapid change in prevailing conditions — typically within 30 minutes. All previous conditions are replaced by the new FM group conditions.', reference: 'AIM 7-1-30' }
        ]
